#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5,M=350;

int len,n,m,sum[M];
bool tag[M],a[N];

int Get(int x){
    return (x-1)/len+1;
}

void modify(int l,int r){
    int p=Get(l),q=Get(r);
    if(p==q){
        for(int i=l;i<=r;i++)
            a[i]^=1,sum[p]+=(a[i]?1:-1);
    }else{
        int i=l;
        for(;Get(i)==p;i++)
            a[i]^=1,sum[p]+=(a[i]?1:-1);
        i=r;
        for(;Get(i)==q;i--)
            a[i]^=1,sum[q]+=(a[i]?1:-1);
        for(i=p+1;i<q;i++)
            tag[i]^=1;
    }
}

int query(int l,int r){
    int p=Get(l),q=Get(r),res=0;
    if(p==q){
        for(int i=l;i<=r;i++)
            res+=a[i]^tag[p];
        return res;
    }
    int i=l;
    for(;Get(i)==p;i++)
        res+=a[i]^tag[p];
    i=r;
    for(;Get(i)==q;i--)
        res+=a[i]^tag[q];
    for(i=p+1;i<q;i++)
        res+=(tag[i]?len-sum[i]:sum[i]);
    return res;
}

int main(){
    scanf("%d%d",&n,&m);
    len=sqrt(n);
    while(m--){
        int tp,a,b;
        scanf("%d%d%d",&tp,&a,&b);
        if(!tp)
            modify(a,b);
        else
            printf("%d\n",query(a,b));
    }
    return 0;
}
